con = duckdb.connect()


def write(name, rows):
    rel = con.from_arrow(__import__("pyarrow").Table.from_pylist(rows))
    out = os.path.join(DATA, name)
    con.register("t", rel)
    con.execute(f"COPY (SELECT * FROM t) TO '{out}' (FORMAT PARQUET, COMPRESSION ZSTD)")
    con.unregister("t")
    n = con.execute(f"SELECT count(*) FROM read_parquet('{out}')").fetchone()[0]
    print(f"  {name}: {n} rows")


print(f"writing parquet to {DATA}")
write("humanoid_meta.parquet", [META])
write("humanoid_joints.parquet", JOINTS)
write("humanoid_cones.parquet", CONES)
write("humanoid_targets.parquet", TARGETS)
print("done")
